const message = $input.first().json.message.text || "";
const chatId = $input.first().json.message.chat.id;
const threadId = $input.first().json.message.message_thread_id || ""; // Hangi odadan geldiğini bulur

if (!message.toLowerCase().startsWith('/roll')) return []; 

let input = message.replace(/^\/roll/i, '').trim().toLowerCase();
if (!input) return [{ json: { chatId, threadId, reply: "Lütfen komut girin. Örn: /roll 1d20 adv veya /roll 1d8+2d8" } }];

let isAdv = input.includes('adv');
let isDis = input.includes('dis');
input = input.replace('adv', '').replace('dis', '').trim();

if (/[^0-9d+\-\s]/.test(input)) {
    return [{ json: { chatId, threadId, reply: "Geçersiz format! Sadece zar, sayı, +, -, adv, dis kullanın." } }];
}

input = input.replace(/\s+/g, '');
let cleanInput = input; 
if (input[0] !== '+' && input[0] !== '-') {
    input = '+' + input;
}

const terms = input.match(/[+-][^+-]+/g);
if (!terms) return [{ json: { chatId, threadId, reply: "Zar okunamadı." } }];

function rollExpression() {
    let total = 0;
    let details = [];

    for (let term of terms) {
        let sign = term[0] === '+' ? 1 : -1;
        let val = term.substring(1);

        if (val.includes('d')) {
            let parts = val.split('d');
            let count = parts[0] === '' ? 1 : parseInt(parts[0]);
            let sides = parseInt(parts[1]);

            let termRolls = [];
            for (let i = 0; i < count; i++) {
                let r = Math.floor(Math.random() * sides) + 1;
                termRolls.push(r);
                total += sign * r;
            }
            details.push(`${sign === 1 ? '+' : '-'}[${termRolls.join(',')}]`);
        } else {
            let num = parseInt(val);
            total += sign * num;
            details.push(`${sign === 1 ? '+' : '-'}${num}`);
        }
    }
    return { total, details: details.join(' ') };
}

let finalReply = "";

if (isAdv || isDis) {
    let r1 = rollExpression();
    let r2 = rollExpression();
    let finalTotal = isAdv ? Math.max(r1.total, r2.total) : Math.min(r1.total, r2.total);
    let cond = isAdv ? "Avantajlı" : "Dezavantajlı";

    finalReply = `🎲 **${cond} Zar:** ${cleanInput}\n1. Atış: ${r1.details} = ${r1.total}\n2. Atış: ${r2.details} = ${r2.total}\n**Sonuç: ${finalTotal}**`;
} else {
    let r = rollExpression();
    finalReply = `🎲 **Zar:** ${cleanInput}\nDetay: ${r.details}\n**Toplam: ${r.total}**`;
}

// Thread ID'yi de bir sonraki düğüme aktar
return [{ json: { chatId, threadId, reply: finalReply } }];
